INSERT INTO posts (title, content, user_id, created_at, updated_at, view_count)
VALUES
('Oasis - Don''t Look Back In Anger', '1995년에 발매된 브릿팝/록 곡입니다. 떼창하기 좋은 후렴과 노엘 갤러거 특유의 멜로디가 매력입니다.', 1, TIMESTAMP '2026-07-01 10:10:00', TIMESTAMP '2026-07-01 10:10:00', 148),
('Oasis - Whatever', '1994년에 발매된 브릿팝/오케스트럴 록 곡입니다. 자유로운 분위기의 스트링 편곡이 돋보입니다.', 2, TIMESTAMP '2026-07-01 10:35:00', TIMESTAMP '2026-07-01 10:35:00', 96),
('Oasis - Little By Little', '2002년에 발매된 브릿팝/록 곡입니다. 담백한 기타 사운드와 성찰적인 가사가 잘 어울립니다.', 3, TIMESTAMP '2026-07-01 11:05:00', TIMESTAMP '2026-07-01 11:05:00', 74),
('RHCP - Can''t Stop', '2002년에 발매된 얼터너티브 록/펑크 록 곡입니다. 반복적인 기타 리프와 강한 그루브가 인상적입니다.', 4, TIMESTAMP '2026-07-01 11:40:00', TIMESTAMP '2026-07-01 11:40:00', 132),
('The Beatles - Octopus''s Garden', '1969년에 발매된 팝 록 곡입니다. 밝고 장난스러운 분위기가 앨범 속에서 편안하게 쉬어 갑니다.', 5, TIMESTAMP '2026-07-01 12:20:00', TIMESTAMP '2026-07-01 12:20:00', 89),
('Stevie Wonder - I Just Called To Say I Love You', '1984년에 발매된 소울 팝/R&B 곡입니다. 단순하지만 따뜻한 고백의 정서가 오래 남습니다.', 6, TIMESTAMP '2026-07-01 13:00:00', TIMESTAMP '2026-07-01 13:00:00', 117),
('Bon Jovi - Livin'' On A Prayer', '1986년에 발매된 하드 록/글램 메탈 곡입니다. 강렬한 후렴과 드라마틱한 전개가 대표적입니다.', 1, TIMESTAMP '2026-07-02 09:15:00', TIMESTAMP '2026-07-02 09:15:00', 173),
('Billy Joel - Piano Man', '1973년에 발매된 소프트 록/싱어송라이터 곡입니다. 피아노와 하모니카가 만드는 서사가 매력입니다.', 2, TIMESTAMP '2026-07-02 09:50:00', TIMESTAMP '2026-07-02 09:50:00', 104),
('Maroon 5 - This Love', '2004년에 발매된 팝 록/펑크 록 곡입니다. 리듬감 있는 피아노 리프와 선명한 훅이 특징입니다.', 3, TIMESTAMP '2026-07-02 10:30:00', TIMESTAMP '2026-07-02 10:30:00', 121),
('Harry Styles - Falling', '2019년에 발매된 팝 발라드 곡입니다. 절제된 피아노와 보컬 감정선이 중심을 잡습니다.', 4, TIMESTAMP '2026-07-02 11:10:00', TIMESTAMP '2026-07-02 11:10:00', 84),
('Green Day - Last Night On Earth', '2009년에 발매된 록 발라드 곡입니다. 밴드의 거친 에너지보다 로맨틱한 멜로디가 앞섭니다.', 5, TIMESTAMP '2026-07-02 12:05:00', TIMESTAMP '2026-07-02 12:05:00', 68),
('Coldplay - Yellow', '2000년에 발매된 얼터너티브 록/팝 록 곡입니다. 따뜻한 기타 톤과 직선적인 고백이 오래 사랑받습니다.', 6, TIMESTAMP '2026-07-02 13:25:00', TIMESTAMP '2026-07-02 13:25:00', 156),
('Jason Mraz - Lucky', '2008년에 발매된 어쿠스틱 팝/포크 팝 곡입니다. 듀엣의 편안한 호흡과 산뜻한 멜로디가 좋습니다.', 1, TIMESTAMP '2026-07-03 09:40:00', TIMESTAMP '2026-07-03 09:40:00', 72),
('Keira Knightley - Tell Me If You Wanna Go Home', '2014년에 공개된 인디 팝/영화 음악 곡입니다. 가볍게 흘러가는 밴드 사운드가 산뜻합니다.', 2, TIMESTAMP '2026-07-03 10:20:00', TIMESTAMP '2026-07-03 10:20:00', 57),
('Aimyon - Kimi Wa Rock Wo Kikanai', '2017년에 발매된 J-팝/록 곡입니다. 청춘의 감정을 솔직하게 담은 기타 팝 감성이 좋습니다.', 3, TIMESTAMP '2026-07-03 11:00:00', TIMESTAMP '2026-07-03 11:00:00', 109),
('Official HIGE DANdism - Pretender', '2019년에 발매된 J-팝/피아노 록 곡입니다. 선명한 멜로디와 애틋한 가사가 강하게 남습니다.', 4, TIMESTAMP '2026-07-03 11:45:00', TIMESTAMP '2026-07-03 11:45:00', 141),
('Leina - Utatane', '2021년에 발매된 J-팝/어쿠스틱 팝 곡입니다. 나른한 보컬과 잔잔한 분위기가 제목처럼 편안합니다.', 5, TIMESTAMP '2026-07-03 12:35:00', TIMESTAMP '2026-07-03 12:35:00', 46),
('검정치마 - Antifreeze', '2010년에 발매된 인디 록/모던 록 곡입니다. 차가운 제목과 달리 선명한 낭만이 살아 있습니다.', 6, TIMESTAMP '2026-07-03 13:10:00', TIMESTAMP '2026-07-03 13:10:00', 118),
('검정치마 - Ling Ling', '2011년에 발매된 인디 록/신스 팝 성향의 곡입니다. 몽환적인 질감과 느슨한 리듬이 매력입니다.', 1, TIMESTAMP '2026-07-04 09:30:00', TIMESTAMP '2026-07-04 09:30:00', 64),
('극동아시아타이거즈 - 다시,다시만나', '2020년대에 공개된 인디 록/밴드 음악 곡입니다. 다시 만나는 순간의 감정을 담백하게 풀어냅니다.', 2, TIMESTAMP '2026-07-04 10:15:00', TIMESTAMP '2026-07-04 10:15:00', 51),
('한로로 - 입춘', '2022년에 발매된 인디 팝/록 곡입니다. 계절이 바뀌는 감각과 섬세한 보컬 톤이 잘 맞닿아 있습니다.', 3, TIMESTAMP '2026-07-04 11:05:00', TIMESTAMP '2026-07-04 11:05:00', 9333);
