INSERT INTO comments (post_id, user_id, content, created_at, updated_at)
VALUES
(1, 2, '인트로만 들어도 바로 기분이 올라가네요.', TIMESTAMP '2026-07-01 10:26:00', TIMESTAMP '2026-07-01 10:26:00'),
(1, 4, '라이브 영상까지 같이 보면 더 좋습니다.', TIMESTAMP '2026-07-01 10:48:00', TIMESTAMP '2026-07-01 10:48:00'),
(1, 6, '후렴에서 다 같이 부르는 맛이 확실해요.', TIMESTAMP '2026-07-01 12:08:00', TIMESTAMP '2026-07-01 12:08:00'),
(2, 1, '스트링 들어오는 순간 분위기가 확 바뀌네요.', TIMESTAMP '2026-07-01 10:52:00', TIMESTAMP '2026-07-01 10:52:00'),
(2, 5, '산책할 때 틀면 진짜 잘 어울릴 것 같아요.', TIMESTAMP '2026-07-01 12:22:00', TIMESTAMP '2026-07-01 12:22:00'),
(3, 2, '이 곡은 후반부로 갈수록 더 좋아요.', TIMESTAMP '2026-07-01 11:35:00', TIMESTAMP '2026-07-01 11:35:00'),
(3, 4, '가사가 은근 오래 남습니다.', TIMESTAMP '2026-07-01 12:06:00', TIMESTAMP '2026-07-01 12:06:00'),
(4, 1, '베이스랑 기타 리프가 미쳤습니다.', TIMESTAMP '2026-07-01 11:55:00', TIMESTAMP '2026-07-01 11:55:00'),
(4, 3, '운동할 때 들으면 텐션 바로 올라가요.', TIMESTAMP '2026-07-01 12:12:00', TIMESTAMP '2026-07-01 12:12:00'),
(4, 6, '뮤직비디오도 같이 추천합니다.', TIMESTAMP '2026-07-01 13:05:00', TIMESTAMP '2026-07-01 13:05:00'),
(5, 3, '링고 보컬이라 더 귀엽게 들려요.', TIMESTAMP '2026-07-01 13:16:00', TIMESTAMP '2026-07-01 13:16:00'),
(5, 6, '앨범 안에서 쉬어 가는 느낌이 좋습니다.', TIMESTAMP '2026-07-01 13:41:00', TIMESTAMP '2026-07-01 13:41:00'),
(6, 1, '가사가 단순한데 그래서 더 직접적으로 와요.', TIMESTAMP '2026-07-01 13:23:00', TIMESTAMP '2026-07-01 13:23:00'),
(6, 4, '부모님 세대도 바로 아는 곡이라 반갑네요.', TIMESTAMP '2026-07-01 14:20:00', TIMESTAMP '2026-07-01 14:20:00'),
(7, 2, '노래방에서 마지막에 꼭 나오는 곡이죠.', TIMESTAMP '2026-07-02 09:34:00', TIMESTAMP '2026-07-02 09:34:00'),
(7, 5, '후렴 시작하면 참기 힘듭니다.', TIMESTAMP '2026-07-02 10:23:00', TIMESTAMP '2026-07-02 10:23:00'),
(7, 6, '조회수 높은 이유가 있네요.', TIMESTAMP '2026-07-02 10:45:00', TIMESTAMP '2026-07-02 10:45:00'),
(8, 1, '이야기를 듣는 것처럼 흘러가서 좋아요.', TIMESTAMP '2026-07-02 10:16:00', TIMESTAMP '2026-07-02 10:16:00'),
(8, 4, '피아노맨은 밤에 들어야 더 좋습니다.', TIMESTAMP '2026-07-02 11:12:00', TIMESTAMP '2026-07-02 11:12:00'),
(9, 2, '초반 피아노 리프가 너무 선명합니다.', TIMESTAMP '2026-07-02 11:16:00', TIMESTAMP '2026-07-02 11:16:00'),
(9, 6, '2000년대 감성이 바로 살아나네요.', TIMESTAMP '2026-07-02 12:08:00', TIMESTAMP '2026-07-02 12:08:00'),
(10, 3, '조용히 들으면 감정선이 훅 들어옵니다.', TIMESTAMP '2026-07-02 12:00:00', TIMESTAMP '2026-07-02 12:00:00'),
(10, 5, '비 오는 날 플레이리스트에 넣어야겠어요.', TIMESTAMP '2026-07-02 12:33:00', TIMESTAMP '2026-07-02 12:33:00'),
(11, 1, '그린데이의 다른 얼굴이라 좋네요.', TIMESTAMP '2026-07-02 12:23:00', TIMESTAMP '2026-07-02 12:23:00'),
(12, 2, '첫 기타 소리만 들어도 바로 알아요.', TIMESTAMP '2026-07-02 13:50:00', TIMESTAMP '2026-07-02 13:50:00'),
(12, 4, '콜드플레이 입문곡으로 최고입니다.', TIMESTAMP '2026-07-02 14:26:00', TIMESTAMP '2026-07-02 14:26:00'),
(12, 5, '커버 이미지랑 곡 분위기가 잘 맞네요.', TIMESTAMP '2026-07-02 14:54:00', TIMESTAMP '2026-07-02 14:54:00'),
(13, 4, '듀엣곡 중에 가장 편하게 듣는 곡입니다.', TIMESTAMP '2026-07-03 10:18:00', TIMESTAMP '2026-07-03 10:18:00'),
(13, 6, '아침에 들으면 하루가 가벼워져요.', TIMESTAMP '2026-07-03 10:48:00', TIMESTAMP '2026-07-03 10:48:00'),
(14, 1, '영화 장면이 같이 떠오르는 노래네요.', TIMESTAMP '2026-07-03 10:41:00', TIMESTAMP '2026-07-03 10:41:00'),
(15, 1, '아이묭 특유의 청춘감이 잘 살아 있어요.', TIMESTAMP '2026-07-03 11:18:00', TIMESTAMP '2026-07-03 11:18:00'),
(15, 5, '기타 톤이 시원해서 계속 듣게 됩니다.', TIMESTAMP '2026-07-03 12:15:00', TIMESTAMP '2026-07-03 12:15:00'),
(16, 2, '멜로디가 너무 강해서 한 번 들으면 남아요.', TIMESTAMP '2026-07-03 12:08:00', TIMESTAMP '2026-07-03 12:08:00'),
(16, 3, '보컬 올라가는 부분이 진짜 좋습니다.', TIMESTAMP '2026-07-03 12:21:00', TIMESTAMP '2026-07-03 12:21:00'),
